describe("Constructor",()=>{describe("Temporal.Instant()",()=>{it("Using Temporal.Instant()",()=>{let t=new Temporal.Instant(0n);expect(t.toString()).toBe("1970-01-01T00:00:00Z");let e=new Temporal.Instant(-275248380000000000n);expect(e.toString()).toBe("1961-04-12T06:07:00Z");let o=new Temporal.Instant(355924804000000000n);expect(o.toString()).toBe("1981-04-12T12:00:04Z")})})});describe("Static methods",()=>{describe("Temporal.Instant.prototype.compare()",()=>{it("Using Temporal.Instant.compare()",()=>{let t=Temporal.Instant.from("2021-08-01T12:34:56Z"),e=Temporal.Instant.from("2021-08-01T12:34:56Z");expect(Temporal.Instant.compare(t,e)).toBe(0);let o=Temporal.Instant.from("2021-08-01T13:34:56Z");expect(Temporal.Instant.compare(t,o)).toBe(-1)})}),describe("Temporal.Instant.prototype.from()",()=>{it("Creating an instant from a string",()=>{let t=Temporal.Instant.from("1970-01-01T00Z");expect(t.toString()).toBe("1970-01-01T00:00:00Z");let e=Temporal.Instant.from("1970-01-01T00+08:00");expect(e.toString()).toBe("1969-12-31T16:00:00Z");let o=Temporal.Instant.from("1970-01-01T00+08:00[America/New_York]");expect(o.toString()).toBe("1969-12-31T16:00:00Z")})}),describe("Temporal.Instant.fromEpochMilliseconds()",()=>{it("Using Temporal.Instant.fromEpochMilliseconds()",()=>{let t=Temporal.Instant.fromEpochMilliseconds(0);expect(t.toString()).toBe("1970-01-01T00:00:00Z");let e=Temporal.Instant.fromEpochMilliseconds(-27524838e4);expect(e.toString()).toBe("1961-04-12T06:07:00Z");let o=Temporal.Instant.fromEpochMilliseconds(355924804e3);expect(o.toString()).toBe("1981-04-12T12:00:04Z")})}),describe("Temporal.Instant.fromEpochNanoseconds()",()=>{it("Using Temporal.Instant.fromEpochNanoseconds()",()=>{let t=Temporal.Instant.fromEpochNanoseconds(0n);expect(t.toString()).toBe("1970-01-01T00:00:00Z");let e=Temporal.Instant.fromEpochNanoseconds(-275248380000000000n);expect(e.toString()).toBe("1961-04-12T06:07:00Z");let o=Temporal.Instant.fromEpochNanoseconds(355924804000000000n);expect(o.toString()).toBe("1981-04-12T12:00:04Z")})})});describe("Instance methods",()=>{describe("Temporal.Instant.prototype.add()",()=>{it("Adding a Temporal.Duration",()=>{let t=Temporal.Instant.fromEpochMilliseconds(0),e=Temporal.Duration.from("PT1S"),o=t.add(e);expect(o.epochMilliseconds).toBe(1e3)}),it("Adding an object or a string",()=>{let t=Temporal.Instant.fromEpochMilliseconds(0),e=t.add({seconds:1});expect(e.epochMilliseconds).toBe(1e3);let o=t.add("PT1S");expect(o.epochMilliseconds).toBe(1e3)}),it("Adding a calendar duration",()=>{let t=Temporal.Instant.fromEpochMilliseconds(173061e7),e=Temporal.Duration.from({days:1}),o=t.toZonedDateTimeISO("America/New_York").add(e).toInstant();expect(o.epochMilliseconds).toBe(17307e8);let n=t.toZonedDateTimeISO("Europe/Paris").add(e).toInstant();expect(n.epochMilliseconds).toBe(17306964e5)})}),describe("Temporal.Instant.prototype.equals()",()=>{it("Using equals()",()=>{let t=Temporal.Instant.from("2021-08-01T12:34:56Z"),e=Temporal.Instant.fromEpochMilliseconds(1627821296e3);expect(t.equals(e)).toBe(!0)})}),describe("Temporal.Instant.prototype.round()",()=>{it("Rounding off small units",()=>{let t=Temporal.Instant.fromEpochMilliseconds(1e3),e=t.round("second");expect(e.epochMilliseconds).toBe(1e3);let o=t.round("minute");expect(o.epochMilliseconds).toBe(0)})}),describe("Temporal.Instant.prototype.since()",()=>{it("since() returns correct duration",()=>{let t=Temporal.Instant.fromEpochMilliseconds(5e3),e=Temporal.Instant.fromEpochMilliseconds(2e3),o=t.since(e);expect(o.years).toBe(0),expect(o.months).toBe(0),expect(o.days).toBe(0),expect(o.hours).toBe(0),expect(o.minutes).toBe(0),expect(o.seconds).toBe(3),expect(o.milliseconds).toBe(0),expect(o.microseconds).toBe(0),expect(o.nanoseconds).toBe(0)})}),describe("Temporal.Instant.prototype.subtract()",()=>{it("Subtracting a Temporal.Duration",()=>{let t=Temporal.Instant.fromEpochMilliseconds(1e3),e=Temporal.Duration.from("PT1S"),o=t.subtract(e);expect(o.epochMilliseconds).toBe(0)})}),describe("Temporal.Instant.prototype.toJSON()",()=>{it("Using toJSON()",()=>{let e=Temporal.Instant.fromEpochMilliseconds(1627821296e3).toJSON();expect(e).toBe("2021-08-01T12:34:56Z")})}),describe("Temporal.Instant.prototype.toString()",()=>{it("Using toString()",()=>{let t=Temporal.Instant.fromEpochMilliseconds(1627814412345);expect(t.toString()).toBe("2021-08-01T10:40:12.344999936Z")})}),describe("Temporal.Instant.prototype.toZonedDateTimeISO()",()=>{it("Using toZonedDateTimeISO()",()=>{let e=Temporal.Instant.from("2021-08-01T12:34:56.123456789Z").toZonedDateTimeISO("America/New_York");expect(e.toString()).toBe("2021-08-01T08:34:56.123456789-04:00[America/New_York]")})}),describe("Temporal.Instant.prototype.until()",()=>{it("until() returns correct duration",()=>{let t=Temporal.Instant.fromEpochMilliseconds(1e3),e=Temporal.Instant.fromEpochMilliseconds(4e3),o=t.until(e);expect(o.years).toBe(0),expect(o.months).toBe(0),expect(o.days).toBe(0),expect(o.hours).toBe(0),expect(o.minutes).toBe(0),expect(o.seconds).toBe(3),expect(o.milliseconds).toBe(0),expect(o.microseconds).toBe(0),expect(o.nanoseconds).toBe(0)})}),describe("Temporal.Instant.prototype.valueOf()",()=>{it("valueOf() throws a TypeError",()=>{let t=Temporal.Instant.fromEpochMilliseconds(0);expect(()=>{+t}).toThrow()})})});describe("Instance properties",()=>{let t=Temporal.Instant.fromEpochMilliseconds(160945926e4);it("reports epochMilliseconds and epochNanoseconds",()=>{expect(typeof t.epochMilliseconds).toBe("number"),expect(t.epochMilliseconds).toBe(160945926e4),expect(typeof t.epochNanoseconds).toBe("bigint"),expect(t.epochNanoseconds).toBe(1609459260000000000n)}),it("has correct toStringTag",()=>{expect(Object.prototype.toString.call(t)).toBe("[object Temporal.Instant]")})});
